import "./main.scss";

const Movie = (props) => {
    const genres = () => {
        let result = ""
        props.movie.genre.forEach(element => {
            result += element + ", "
        });
        return genresList
    }
    return (
        <li className="item">
            <img src={props.movie.image} />
            <details>
                <summary>
                    <div>
                        <h5>{props.movie.name}</h5>
                        <p className="Genre">{genres()}</p>
                    </div>
                    <div>
                        <i className="fas fa-star"></i>
                        <span className="rating">{props.movie.imdb_rating}</span>
                    </div>
                </summary>
            </details>
        </li>
    );
}


export default Movie;
